class Solution:
    def containVirus(self, isInfected):
        m = len(isInfected)
        n = len(isInfected[0])
        grid = [row[:] for row in isInfected]
        total = 0
        def neighbours(r, c):
            for dr, dc in ((1,0),(-1,0),(0,1),(0,-1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n:
                    yield nr, nc
        while True:
            seen = [[False]*n for _ in range(m)]
            regions = []
            for i in range(m):
                for j in range(n):
                    if grid[i][j] == 1 and not seen[i][j]:
                        cells = []
                        threat = set()
                        walls = 0
                        stack = [(i, j)]
                        seen[i][j] = True
                        while stack:
                            r, c = stack.pop()
                            cells.append((r, c))
                            for nr, nc in neighbours(r, c):
                                if grid[nr][nc] == 1 and not seen[nr][nc]:
                                    seen[nr][nc] = True
                                    stack.append((nr, nc))
                                elif grid[nr][nc] == 0:
                                    threat.add((nr, nc))
                                    walls += 1
                        regions.append((cells, threat, walls))
            active = [reg for reg in regions if reg[1]]
            if not active:
                break
            target = max(active, key=lambda reg: len(reg[1]))
            total += target[2]
            for (r, c) in target[0]:
                grid[r][c] = 2
            for (cells, threat, walls) in active:
                if cells is target[0]:
                    continue
                for (r, c) in threat:
                    grid[r][c] = 1
        return total

