                    if grid[i][j] == 1 and not visited[i][j]:
                        body = []
                        frontier = set()
                        wall_count = 0
                        stack = [(i, j)]
                        visited[i][j] = True
                        while stack:
                            r, c = stack.pop()
                            body.append((r, c))
                            for dr, dc in DIRS:
                                nr, nc = r + dr, c + dc
                                if 0 <= nr < m and 0 <= nc < n:
                                    if grid[nr][nc] == 1 and not visited[nr][nc]:
                                        visited[nr][nc] = True
                                        stack.append((nr, nc))
                                    elif grid[nr][nc] == 0:
                                        frontier.add((nr, nc))
                                        wall_count += 1
                        regions.append((body, frontier, wall_count))
            threatening = [reg for reg in regions if reg[1]]
            if not threatening:
                break
            idx = max(range(len(threatening)), key=lambda k: len(threatening[k][1]))
            walls_used += threatening[idx][2]
            for k, (body, frontier, wall_count) in enumerate(threatening):
                if k == idx:
