var containVirus = function(isInfected) {
    const m = isInfected.length, n = isInfected[0].length;
    const grid = isInfected.map(row => row.slice());
    const DIRS = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    let wallsUsed = 0;
    while (true) {
        const visited = Array.from({length: m}, () => new Array(n).fill(false));
        const regions = [];
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (grid[i][j] === 1 && !visited[i][j]) {
                    const body = [];
                    const frontier = new Set();
                    let wallCount = 0;
                    const stack = [[i, j]];
                    visited[i][j] = true;
                    while (stack.length) {
                        const [r, c] = stack.pop();
                        body.push([r, c]);
                        for (const [dr, dc] of DIRS) {
                            const nr = r + dr, nc = c + dc;
                            if (nr >= 0 && nr < m && nc >= 0 && nc < n) {
                                if (grid[nr][nc] === 1 && !visited[nr][nc]) {
                                    visited[nr][nc] = true;
                                    stack.push([nr, nc]);
                                } else if (grid[nr][nc] === 0) {
                                    frontier.add(nr * n + nc);
                                    wallCount++;
                                }
                            }
                        }
                    }
                    regions.push({body, frontier, wallCount});
                }
            }
        }
        const threatening = regions.filter(reg => reg.frontier.size > 0);
        if (threatening.length === 0) break;
        let idx = 0;
        for (let k = 1; k < threatening.length; k++) {
            if (threatening[k].frontier.size > threatening[idx].frontier.size) idx = k;
        }
        wallsUsed += threatening[idx].wallCount;
        for (let k = 0; k < threatening.length; k++) {
            if (k === idx) {
                for (const [r, c] of threatening[k].body) grid[r][c] = 2;
            } else {
                for (const cell of threatening[k].frontier) {
                    const r = Math.floor(cell / n), c = cell % n;
                    grid[r][c] = 1;
                }
            }
        }
    }
    return wallsUsed;
};
